module.exports = {
  config: {
cooldowns: 10,
credits: 'CHAND',
premium: false,
permission: 0,
version: '1.0.0',
    name: 'setcolor',
    aliases: ['setcolor', 'groupcolor', 'gpcolor'],
    description: 'Change group chat color/theme',
    usage: 'color [color name]',
    category: 'Group Management',
    adminOnly: true,
    groupOnly: true,
    prefix: true
  },

  async run({ api, event, args, send }) {
    const { threadID } = event;

    if (!args.length) {
      return send.reply(`━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n🎨 🅐𝐯𝐚𝐢𝐥𝐚𝐛𝐥𝐞 🅣𝐡𝐞𝐦𝐞 🅒𝐨𝐥𝐨𝐫𝐬:\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🅑𝐚𝐬𝐢𝐜 🅒𝐨𝐥𝐨𝐫𝐬:\nDefaultBlue, Red, TealBlue, Yellow, Orange, Green,\nLavenderPurple, HotPink, AquaBlue, BrightPurple,\nCoralPink\n🅢𝐩𝐞𝐜𝐢𝐚𝐥 🅣𝐡𝐞𝐦𝐞𝐬:\nAqua, Mango, Berry, Citrus, Candy, Earth, Support,\nMusic, Pride, DoctorStrange, LoFi, Sky,\nLunarNewYear, Celebration, Chill, StrangerThings,\nDune, Care, Astrology, Birthday, Cottagecore, Ocean,\nLove, TieDye, Monochrome, Rocket, Unicorn, Tropical,\nMaple, Sushi, Shadow, Rose, Lavender, Tulip,\nClassic, Peach, Honey, Kiwi, Grape, NonBinary,\nTransgender, TaylorSwift, Autumn, Cyberpunk2077,\n& many more!\n📌 🅤𝐬𝐚𝐠𝐞: .color [color_name]\n🅔𝐱𝐚𝐦𝐩𝐥𝐞: .color blue\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━`);
    }

    const colorName = args.join(' ').trim();
    const colorMap = getColorMap();
    
    // Find color (case-insensitive)
    let colorID = null;
    for (const [key, value] of Object.entries(colorMap)) {
      if (key.toLowerCase() === colorName.toLowerCase()) {
        colorID = value;
        break;
      }
    }

    if (!colorID) {
      return send.reply(`━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n🅒𝐨𝐥𝐨𝐫 "${colorName}" 𝐧𝐨𝐭 𝐟𝐨𝐮𝐧𝐝.\n\n🅣𝐫𝐲 .color 𝐟𝐨𝐫 𝐚 𝐥𝐢𝐬𝐭 𝐨𝐟 𝐚𝐯𝐚𝐢𝐥𝐚𝐛𝐥𝐞 𝐜𝐨𝐥𝐨𝐫𝐬.\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━`);
    }

    try {
      await api.changeThreadColor(colorID, threadID);
      return send.reply(`━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n✅ 🅖𝐫𝐨𝐮𝐩 𝐭𝐡𝐞𝐦𝐞 𝐜𝐡𝐚𝐧𝐠𝐞𝐝 𝐭𝐨 ${colorName}! 🎨\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━`);
    } catch (error) {
      return send.reply(`❌ Failed to change color: ${error.message}`);
    }
  }
};

